module shift_register(clk, load, in, shift, out);
    input clk, load, shift;
    input [3:0] in;
    output [3:0] out;
    reg [3:0] unused_reg_out;

    always @(posedge clk) begin
        if (load) begin
            unused_reg_out <= in;
        end else if (shift) begin
            unused_reg_out <= {unused_reg_out[2:0], 1'b0};
        end
    end

    assign out = unused_reg_out;
endmodule
